def assess(record: dict) -> str:
    required_fields = {"case_id", "event_time", "window_end", "watermark", "allowed_lateness"}
    absent = sorted(required_fields - set(record))
    if absent:
        return "MISSING:" + ",".join(absent)
    ok = not (record["event_time"] > record["window_end"] or record["event_time"] < record["watermark"] - record["allowed_lateness"])
    return "PASS" if ok else "SIDE_OUTPUT_LATE_EVENT"

valid = {"case_id": "CASO-HYO-046-1A", **{"event_time": 110, "window_end": 120, "watermark": 115, "allowed_lateness": 10}}
invalid = {"case_id": "CASO-HYO-046-1A", **{"event_time": 0, "window_end": 120, "watermark": 115, "allowed_lateness": 10}}
incomplete = dict(valid)
if "allowed_lateness" in incomplete:
    del incomplete["allowed_lateness"]
results = (assess(valid), assess(invalid), assess(incomplete))
print(*results)

